# Category: datastore_security

import re
from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

redis_client = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)

# Allowlist of safe Redis commands
ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'PTTL',
    'KEYS', 'MGET', 'MSET', 'INCR', 'DECR', 'INCRBY', 'DECRBY',
    'APPEND', 'STRLEN', 'GETRANGE', 'SETEX', 'PSETEX', 'SETNX',
    'HGET', 'HSET', 'HDEL', 'HGETALL', 'HKEYS', 'HVALS', 'HEXISTS', 'HLEN',
    'HMGET', 'HMSET', 'HINCRBY',
    'LPUSH', 'RPUSH', 'LPOP', 'RPOP', 'LLEN', 'LRANGE', 'LINDEX', 'LSET',
    'SADD', 'SREM', 'SMEMBERS', 'SISMEMBER', 'SCARD', 'SUNION', 'SINTER',
    'ZADD', 'ZREM', 'ZRANGE', 'ZREVRANGE', 'ZSCORE', 'ZCARD', 'ZRANK',
    'DBSIZE', 'PING', 'ECHO', 'TYPE', 'RANDOMKEY', 'SCAN',
    'INFO',
}

# Explicitly denied dangerous commands
DENIED_COMMANDS = {
    'FLUSHALL', 'FLUSHDB', 'SHUTDOWN', 'CONFIG', 'DEBUG',
    'EVAL', 'EVALSHA', 'SCRIPT', 'SLAVEOF', 'REPLICAOF',
    'MODULE', 'ACL', 'BGSAVE', 'BGREWRITEAOF', 'SAVE',
    'MIGRATE', 'CLUSTER', 'CLIENT', 'COMMAND', 'LATENCY',
    'MEMORY', 'OBJECT', 'PFDEBUG', 'PSYNC', 'REPLCONF',
    'RESTORE', 'SORT', 'SWAPDB', 'WAIT', 'MONITOR',
}

# Pattern to validate key names - prevent injection via key names
KEY_PATTERN = re.compile(r'^[a-zA-Z0-9_\-\.\:\*\[\]]+$')

MAX_ARGS = 20
MAX_ARG_LENGTH = 4096


def parse_command_string(command_string):
    """Parse a command string into command name and arguments."""
    if not command_string or not command_string.strip():
        return None, []

    parts = command_string.strip().split()
    if not parts:
        return None, []

    command_name = parts[0].upper()
    args = parts[1:]

    return command_name, args


def validate_command(command_name, args):
    """Validate that the command is allowed and arguments are safe."""
    errors = []

    if command_name in DENIED_COMMANDS:
        errors.append(f"Command '{command_name}' is explicitly denied for security reasons.")
        return errors

    if command_name not in ALLOWED_COMMANDS:
        errors.append(
            f"Command '{command_name}' is not in the allowlist. "
            f"Allowed commands: {', '.join(sorted(ALLOWED_COMMANDS))}"
        )
        return errors

    if len(args) > MAX_ARGS:
        errors.append(f"Too many arguments ({len(args)}). Maximum allowed: {MAX_ARGS}.")

    for i, arg in enumerate(args):
        if len(arg) > MAX_ARG_LENGTH:
            errors.append(
                f"Argument {i + 1} exceeds maximum length ({len(arg)} > {MAX_ARG_LENGTH})."
            )

    # For KEYS command, restrict patterns to prevent overly broad scans
    if command_name == 'KEYS' and args:
        pattern = args[0]
        if pattern == '*':
            errors.append(
                "Wildcard-only KEYS pattern ('*') is not allowed. "
                "Use a more specific pattern like 'prefix:*' or use SCAN instead."
            )

    return errors


def sanitize_response(response):
    """Sanitize Redis response for JSON serialization."""
    if response is None:
        return None
    if isinstance(response, bytes):
        try:
            return response.decode('utf-8')
        except UnicodeDecodeError:
            return response.hex()
    if isinstance(response, list):
        return [sanitize_response(item) for item in response]
    if isinstance(response, dict):
        return {
            sanitize_response(k): sanitize_response(v)
            for k, v in response.items()
        }
    if isinstance(response, set):
        return [sanitize_response(item) for item in response]
    return response


@app.route('/api/admin/redis', methods=['POST'])
def execute_redis_command():
    """Execute a validated Redis command."""
    # Check for API key authentication
    api_key = request.headers.get('X-API-Key')
    if not api_key or api_key != app.config.get('ADMIN_API_KEY', 'change-me-in-production'):
        return jsonify({
            'success': False,
            'error': 'Unauthorized. Valid API key required.'
        }), 401

    command_string = request.args.get('command', '').strip()

    if not command_string:
        return jsonify({
            'success': False,
            'error': 'Missing required parameter: command'
        }), 400

    command_name, args = parse_command_string(command_string)

    if not command_name:
        return jsonify({
            'success': False,
            'error': 'Could not parse command.'
        }), 400

    validation_errors = validate_command(command_name, args)
    if validation_errors:
        return jsonify({
            'success': False,
            'error': 'Command validation failed.',
            'details': validation_errors
        }), 403

    try:
        result = redis_client.execute_command(command_name, *args)
        sanitized_result = sanitize_response(result)

        return jsonify({
            'success': True,
            'command': command_name,
            'args': args,
            'result': sanitized_result
        }), 200

    except redis.RedisError as e:
        return jsonify({
            'success': False,
            'error': f'Redis error: {str(e)}',
            'command': command_name
        }), 500
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f'Unexpected error: {str(e)}'
        }), 500


@app.route('/api/admin/redis/allowed-commands', methods=['GET'])
def list_allowed_commands():
    """List all allowed Redis commands."""
    api_key = request.headers.get('X-API-Key')
    if not api_key or api_key != app.config.get('ADMIN_API_KEY', 'change-me-in-production'):
        return jsonify({
            'success': False,
            'error': 'Unauthorized. Valid API key required.'
        }), 401

    return jsonify({
        'success': True,
        'allowed_commands': sorted(ALLOWED_COMMANDS),
        'total': len(ALLOWED_COMMANDS)
    }), 200


@app.route('/api/admin/redis/health', methods=['GET'])
def redis_health():
    """Check Redis connection health."""
    api_key = request.headers.get('X-API-Key')
    if not api_key or api_key != app.config.get('ADMIN_API_KEY', 'change-me-in-production'):
        return jsonify({
            'success': False,
            'error': 'Unauthorized. Valid API key required.'
        }), 401

    try:
        ping_result = redis_client.ping()
        info = redis_client.info(section='server')
        return jsonify({
            'success': True,
            'redis_connected': ping_result,
            'redis_version': info.get('redis_version', 'unknown'),
            'uptime_seconds': info.get('uptime_in_seconds', 'unknown')
        }), 200
    except redis.RedisError as e:
        return jsonify({
            'success': False,
            'redis_connected': False,
            'error': str(e)
        }), 503


